UPDATE tours SET 
  name = 'Khám phá Đài Loan 5 Ngày 4 Đêm',
  inclusions = '<p><b>Vận Chuyển:</b></p><br/><p>- Vé máy bay khứ hồi theo đoàn (23kg hành lý ký gửi + xách tay 5kg)</p><p>- Xe máy lạnh vận chuyển suốt tuyến.</p><p>- Phí an ninh sân bay, bảo hiểm hàng không, thuế phi trường 2 nước (có thể thay đổi tại thời điểm xuất vé).</p><br/><p><b>Lưu Trú:</b></p><br/><p>- Khách sạn tiêu chuẩn 4* địa phương (2 khách/phòng, khách lẻ nam/nữ có thể bố trí phòng phù hợp).</p><br/><p><b>Dịch Vụ Khác:</b></p><br/><p>- Visa đoàn nhập cảnh Trung Quốc (áp dụng cho khách hộ chiếu Việt Nam).</p><p>- Vé tham quan theo chương trình.</p><p>- Các bữa ăn theo lịch trình (đảm bảo số lượng & chất lượng tương đương nếu có điều chỉnh).</p><p>- Nước suối 01 chai/khách/ngày.</p><p>- Bảo hiểm du lịch quốc tế.</p><p>- Trưởng đoàn và HDV địa phương phục vụ suốt hành trình.</p><p>- Thuế VAT.</p>',
  exclusions = '<p>- Phụ thu phòng đơn: 3.000.000 đ/khách/tour. Lễ Tết: 5.500.000 đ/khách/tour.</p><p>- Tips cho tài xế và hướng dẫn viên: 25 USD/khách/tour.</p><p>- Visa tái nhập Việt Nam cho khách quốc tịch nước ngoài theo quy định hiện hành (nếu có).</p><p>- Chi phí cá nhân: hành lý quá cước, điện thoại, giặt ủi, tham quan, chi tiêu ngoài chương trình, ...</p>'
WHERE id = 2;


