ON DUPLICATE KEY UPDATE
    code = VALUES(code), name = VALUES(name), slug = VALUES(slug), short_description = VALUES(short_description),
    description = VALUES(description), highlights = VALUES(highlights), inclusions = VALUES(inclusions), exclusions = VALUES(exclusions),
    duration_days = VALUES(duration_days), duration_nights = VALUES(duration_nights), max_group_size = VALUES(max_group_size),
    min_age = VALUES(min_age), base_price = VALUES(base_price), list_price = ROUND(VALUES(base_price) * 1.18),
    esg_score = 72 + MOD(VALUES(id) * 7, 24), lei_score = 70 + MOD(VALUES(id) * 11, 26),
    currency = VALUES(currency), trip_mode = VALUES(trip_mode), status = 'active', is_featured = VALUES(is_featured), deleted_at = NULL;










