INSERT INTO tour_itinerary_days (id, tour_id, day_number, title, description, day_image_url) VALUES 
(2001, 2, 1, 'HCM - Đài Bắc (Ăn Khuya Trên Máy Bay)', '22h30: Quý khách tập trung tại sân bay Quốc tế Tân Sơn Nhất, làm thủ tục chuyến bay BR382 01:55 - 06:10 đi Đài Bắc. Quý khách ăn khuya nhẹ và nghỉ đêm trên máy bay.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?auto=format&fit=crop&q=80&w=1200'),
(2002, 2, 2, 'Đài Bắc - Cao Hùng (Ăn Sáng, Trưa, Tối)', 'Đoàn đáp sân bay quốc tế Đào Viên, làm thủ tục nhập cảnh. Xe và HDV đón đoàn, di chuyển đi dùng bữa sáng. Sau đó khởi hành đi Cao Hùng.', 'https://images.unsplash.com/photo-1607082348824-0a96f2a4b9da?auto=format&fit=crop&q=80&w=1200'),
(2003, 2, 3, 'Cao Hùng - Đài Trung (Ăn Sáng, Trưa, Tối)', 'Đoàn ăn sáng, trả phòng khởi hành đi Đài Trung. Khám phá vẻ đẹp thiên nhiên và văn hóa đặc sắc.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?auto=format&fit=crop&q=80&w=1200'),
(2004, 2, 4, 'Đài Trung - Đài Bắc (Ăn Sáng, Trưa)', 'Tham quan những công trình kiến trúc độc đáo và thưởng thức ẩm thực đặc sắc của Đài Loan.', 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&q=80&w=1200'),
(2005, 2, 5, 'Đài Bắc - HCM (Ăn Sáng, Trưa, Tối Trên Máy Bay)', 'Mua sắm đặc sản và khởi hành về Việt Nam, kết thúc chuyến hành trình.', 'https://images.unsplash.com/photo-1464349153735-7db50ed83c84?auto=format&fit=crop&q=80&w=1200');
INSERT INTO itinerary_items (itinerary_day_id, sequence_no, item_type, title, description, location_name, start_time, end_time, image_url, image_caption) VALUES 
(2002, 1, 'activity', 'Bảo tàng Kỳ Mỹ', 'Một trong những bảo tàng đắt giá nhất thế giới, sở hữu bộ sưu tập nghệ thuật & lịch sử độc đáo.', 'Chimei Museum', '08:00:00', '10:00:00', 'https://images.unsplash.com/photo-1464349153735-7db50ed83c84?auto=format&fit=crop&q=80&w=800', 'Bảo tàng Kỳ Mỹ (Chimei Museum)'),
(2002, 2, 'activity', 'Phật Quang Sơn Tự', 'Trải nghiệm văn hóa Phật giáo đậm nét tại thủ đô Phật Giáo Đài Nam, thánh địa Phật Giáo cực kỳ nổi tiếng với lối kiến trúc đồ sộ hùng vĩ.', 'Phật Quang Sơn', '10:30:00', '12:00:00', 'https://images.unsplash.com/photo-1488646953014-85cb44e25828?auto=format&fit=crop&q=80&w=800', 'Sự thiền tịnh yên bình tại Phật Quang Sơn Tự'),
(2002, 3, 'activity', 'Trạm tàu điện Formosa Boulevard', 'Công trình nghệ thuật độc đáo với 4500 tấm kính, tạo nên mái vòm ánh sáng lớn nhất thế giới.', 'Formosa Boulevard', '14:00:00', '15:30:00', 'https://images.unsplash.com/photo-1493246507139-91e8fad9978e?auto=format&fit=crop&q=80&w=800', 'Vẻ đẹp lấp lánh của trạm tàu điện Formosa Boulevard');
INSERT INTO itinerary_items (itinerary_day_id, sequence_no, item_type, title, description, location_name, start_time, end_time, image_url, image_caption) VALUES 
(2003, 1, 'activity', 'Trải nghiệm du thuyền Nhật Nguyệt Đàm', 'Một viên ngọc quý của thiên nhiên, nơi hồ nước tự nhiên lớn nhất Đài Loan hòa quyện cùng vẻ đẹp hùng vĩ của núi rừng.', 'Nhật Nguyệt Đàm', '09:00:00', '11:00:00', 'https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&q=80&w=800', 'Du thuyền ngoạn cảnh Nhật Nguyệt Đàm'),
(2003, 2, 'activity', 'Văn Võ Miếu', 'Nằm ở phía Bắc hồ Nhật Nguyệt có tượng sư tử bằng đá to lớn uy nghi trấn cửa bên trong, thờ Khổng Tử và hai đồ đệ của ông.', 'Văn Võ Miếu', '13:00:00', '14:30:00', 'https://images.unsplash.com/photo-1540959733332-e9ab65c8a681?auto=format&fit=crop&q=80&w=800', 'Vẻ uy nghiêm của Văn Võ Miếu'),
(2003, 3, 'activity', 'Nhà hát Quốc Gia Đài Trung', 'Công trình kiến trúc độc đáo lấy cảm hứng từ những hang động thiên nhiên. Với những buồng kính xuyên thấu đặc biệt, vinh danh kiến trúc mới.', 'Nhà hát Quốc gia', '16:00:00', '17:30:00', 'https://images.unsplash.com/photo-1607082348824-0a96f2a4b9da?auto=format&fit=crop&q=80&w=800', 'Kiến trúc ấn tượng của Nhà hát Quốc gia Đài Trung');
INSERT INTO itinerary_items (itinerary_day_id, sequence_no, item_type, title, description, location_name, start_time, end_time, image_url, image_caption) VALUES 
(2004, 1, 'activity', 'Lớp học làm bánh dứa', 'Tự tay làm nên những chiếc bánh dứa đặc sắc Đài Loan tại điểm dừng chân DIY.', 'Điểm mua sắm DIY', '09:00:00', '10:30:00', 'https://images.unsplash.com/photo-1488646953014-85cb44e25828?auto=format&fit=crop&q=80&w=800', 'Bánh Dứa đặc sản của Đài Loan'),
(2004, 2, 'activity', 'Tháp Taipei 101', 'Tòa nhà cao thứ nhì Đài Loan, biểu tượng tiêu biểu thu hút nhiều du khách check-in.', 'Tháp Taipei 101', '14:00:00', '16:00:00', 'https://images.unsplash.com/photo-1527631746610-bca00a040d60?auto=format&fit=crop&q=80&w=800', 'Tháp Taipei 101 bề thế'),
(2004, 3, 'activity', 'Nhà tưởng niệm Tưởng Giới Thạch', 'Công trình kiến trúc văn hóa tiêu biểu nằm trong quảng trường Trung Chính rộng lớn.', 'Nhà tưởng niệm', '16:30:00', '18:00:00', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?auto=format&fit=crop&q=80&w=800', 'Nhà tưởng niệm uy nghi');
